    pub_data = json.load(f)

level5_symbols = set()
for r in level5_data:
    s = r.get('symbol')
    if s:
        level5_symbols.add(s.strip().upper())

# helper to find a year in a text: look for any 4-digit substring starting with 19 or 20
def extract_year(text):
    if not isinstance(text, str):
        return None
    for i in range(len(text)-3):
        part = text[i:i+4]
        if (part.startswith('19') or part.startswith('20')) and part.isdigit():
            return int(part)
    return None

counts = {}
min_year = 9999
max_year = 0

for rec in pub_data:
    fd = rec.get('filing_date') or ''
    year = extract_year(fd)
    if year is None:
        continue
    if year < min_year:
        min_year = year
    if year > max_year:
        max_year = year
    cpc_field = rec.get('cpc')
    if not cpc_field:
        continue
    # parse cpc JSON
    try:
        cpcs = json.loads(cpc_field)
    except Exception:
        try:
            cpcs = json.loads(cpc_field.replace('\n',''))
        except Exception:
            continue
    if not isinstance(cpcs, list):
        continue
    for item in cpcs:
        if isinstance(item, dict):
            code = item.get('code')
        else:
            code = None
        if not code:
            continue
        code = code.strip().upper()
        # extract group: first 4 chars if pattern Letter Digit Digit Letter
        group = code[:4]
        if len(group)==4 and group[0].isalpha() and group[1].isdigit() and group[2].isdigit() and group[3].isalpha():
            pass
        else:
            group = code[:4]
        if group in level5_symbols:
            counts[(group, year)] = counts.get((group, year), 0) + 1

rows = []
for (g,y),cnt in counts.items():
    rows.append({'group':g, 'year':int(y), 'count':int(cnt)})

selected = []
if rows:
    df = pd.DataFrame(rows)
    all_groups = sorted(df['group'].unique())
    years = list(range(min_year, max_year+1))
    full_rows = []
    for g in all_groups:
        for y in years:
            c = int(df[(df['group']==g)&(df['year']==y)]['count'].sum())
