    # determine groups
    groups = sorted({g for (g,y) in counts.keys()})
    years = list(range(min_year, max_year+1))
    for g in groups:
        # compute series
        ema = None
        best_ema = -1.0
        best_year = None
        for y in years:
            x = counts.get((g,y), 0)
            if ema is None:
